8	import Foundation
9	
10	@Observable
11	final class AlarmLevelSetupViewModel {
12	    
13	    private final class LastState {
14	        var last1: Decimal
15	        var last2: Decimal
16	        
17	        init(last1: Decimal, last2: Decimal) {
18	            self.last1 = last1
19	            self.last2 = last2
20	        }
21	    }
22	    
23	    private let alarmLevel: Alarm.Level
24	    
25	    var displayedValueLevel1: AlarmWheelModel
26	    var displayedValueLevel2: AlarmWheelModel
27	            
28	    init(alarmLevel: Alarm.Level) {
29	        self.alarmLevel = alarmLevel
30	        let radiationType = alarmLevel.radiationType
31	       
32	        func makeValues(minStep: Decimal, switchAt: Decimal) -> [Decimal] {
33	            let rawMax = alarmLevel.offScale ?? radiationType.defaultMaxValue
34	
35	            func step(for value: Decimal) -> Decimal {
36	                var step = minStep
37	                var threshold = switchAt
38	
39	                while value >= threshold * 10 {
40	                    step *= 10
41	                    threshold *= 10
42	                }
43	
44	                return step
45	            }
46	
47	            let topStep = step(for: rawMax)
48	            var ceiled = Decimal()
49	            var divided = rawMax / topStep
50	            NSDecimalRound(&ceiled, &divided, 0, .up)
51	            let maxValue = ceiled * topStep
52	            
53	            var values: [Decimal] = []
54	            var value = maxValue
55	
56	            while value >= 0 {
57	                values.append(value)
58	                if value == 0 { break }
59	
60	                value -= step(for: value)
61	                if value < 0 {
62	                    value = 0
63	                }
64	            }
65	
66	            return values
67	        }
68	        
69	        let values: [Decimal] = {
70	            switch radiationType {
71	            case .radiationLevel(let level):
72	                switch level {
73	                case .countRate:
74	                    makeValues(minStep: 0.1, switchAt: 20)
75	
76	                case .doseRate:
77	                    makeValues(minStep: 0.01, switchAt: 2)
78	                }
79	
80	            case .dose:
81	                makeValues(minStep: 1, switchAt: 100)
82	            }
83	        }()
84	        
85	        self.displayedValueLevel1 = .init(initialValue: alarmLevel.level1 ?? 0, radiationType: radiationType, values: values)
86	        self.displayedValueLevel2 = .init(initialValue: alarmLevel.level2 ?? 0, radiationType: radiationType, values: values)
87	
88	        let state = LastState(last1: displayedValueLevel1.selectedValue, last2: displayedValueLevel2.selectedValue)
89	
90	        withObservationTracking { [weak self] in
91	            guard let self else { return }
92	            let level1 = self.displayedValueLevel1.selectedValue
93	            let level2 = self.displayedValueLevel2.selectedValue
94	            
95	            let level1Changed = (level1 != state.last1)
96	            let level2Changed = (level2 != state.last2)
97	
98	            defer {
99	                state.last1 = level1
100	                state.last2 = level2
101	            }
102	            
103	            if level2Changed && !level1Changed {
104	                // двигают level2 -> level1 следует за ним
105	                if level2 < level1 {
106	                    self.displayedValueLevel1.selectedValue = level2
107	                }
108	            } else if level1Changed && !level2Changed {
109	                // двигают level1 -> level2 следует за ним
110	                if level1 > level2 {
111	                    self.displayedValueLevel2.selectedValue = level1
112	                }
113	            }
114	        }
115	    }
116	    
117	    func alarmsChanged() -> Bool {
118	        alarmLevel.level1 != displayedValueLevel1.selectedValue || alarmLevel.level2 != displayedValueLevel2.selectedValue
119	    }
120	}
