22	    
23	    init(handling: DoseSettings.BackgroundHandling, doseSettings: DoseSettings) {
24	        self.handling = handling
25	        self.doseSettings = doseSettings
26	        let value: Decimal
27	        switch handling {
28	        case .substract:
29	            self.title = .Dose.annualReferenceLevelBgSubtracted
30	            value = doseSettings.annualBackgroundSubstractValue
31	        case .include:
32	            self.title = .Dose.annualReferenceLevelBgIncluded
33	            value = doseSettings.annualBackgroundIncludeValue
34	           
35	        }
36	        self._dose = .init(initialValue: .init(initialValue: value, radiationType: .dose, values: Consts.values))
37	    }
38	    
39	    var body: some View {
40	        NavigationStack {
41	            VStack {
42	                OnboardingPageView(
43	                    title: title,
44	                    subtitle: .Dose.historyPersonalDoseComparisonDescription) {
45	
46	                        AlarmLevelRowView(
47	                            title: .Dose.perYear,
48	                            color: .accentBlue,
49	                            model: dose
50	                        )
51	                        .padding(.bottom, 100)
52	                }
53	                
54	                Button(.Base.save) {
55	                    switch handling {
56	                    case .substract:
57	                        doseSettings.annualBackgroundSubstractValue = dose.selectedValue
58	                    case .include:
59	                        doseSettings.annualBackgroundIncludeValue = dose.selectedValue
60	                    }
61	                    dismiss()
62	                }
63	                .buttonStyle(.pill)
64	                .padding(.horizontal, 35)
65	            }
66	            .navigationTitle(.Dose.referenceLevel)
67	            .navigationBarTitleDisplayMode(.inline)
68	            .toolbar {
69	                CloseButton()
70	            }
71	        }
72	    }
73	}
