8	import Foundation
9	import FactoryKit
10	
11	@Observable
12	final class DoseSelectBackgroundLevelViewModel {
13	 
14	    enum BackgroundLevelMode: Equatable {
15	        case auto
16	        case manual
17	    }
18	    
19	    private enum Consts {
20	        static let defaultDoseManualValue: Decimal = 0.05
21	        static let doseManualValues: [Decimal] = Array(stride(from: 0, through: 2, by: 0.01)).reversed()
22	    }
23	    
24	    @ObservationIgnored
25	    @Injected(\.radiaverseDoseFetchService) private var radiaverseDoseFetchService
26	    
27	    var mode: BackgroundLevelMode
28	    
29	    var manualDose: AlarmWheelModel = .init(
30	        initialValue: Consts.defaultDoseManualValue,
31	        radiationType: .radiationLevel(.doseRate),
32	        values: Consts.doseManualValues
33	    )
34	
35	    var coordinates: Coordinates? = nil
36	    var doseValue: Decimal? = nil
37	
38	    var isValid: Bool {
39	        switch mode {
40	        case .manual:
41	            true
42	        case .auto:
43	            doseValue != nil
44	        }
45	    }
46	    
47	    private let initialSettings: DoseSettings?
48	    private let shouldAutoUpdateSettingsOnLoad: Bool
49	    
50	    private var currentAutoBackgroundLevel: DoseSettings.BackgroundLevel? {
51	        guard let doseValue, let coordinates else { return nil }
52	        return .init(
53	            value: doseValue,
54	            mode: .auto(coordinates: coordinates, date: .now)
55	        )
56	    }
57	    
58	    init() {
59	        initialSettings = nil
60	        shouldAutoUpdateSettingsOnLoad = false
61	        mode = .auto
62	        loadDose()
63	    }
64	    
65	    init(initialSettings: DoseSettings) {
66	        self.initialSettings = initialSettings
67	        let initialDose = initialSettings.backgroundLevel
68	        self.shouldAutoUpdateSettingsOnLoad = initialDose.isAuto
69	
70	        switch initialDose.mode {
71	        case .manual:
72	            self.mode = .manual
73	            self.manualDose.selectedValue = initialDose.value
74	        case .auto:
75	            self.mode = .auto
76	        }
77	        loadDose()
78	    }
79	    
80	    private func loadDose() {
81	        Task {
82	            do {
83	                let result = try await radiaverseDoseFetchService.fetchCurrentDose()
84	                await MainActor.run {
85	                    self.coordinates = result.coordinates
86	                    self.doseValue = result.dose
87	                }
88	                guard shouldAutoUpdateSettingsOnLoad else { return }
89	                guard let currentAutoBackgroundLevel else { return }
90	                self.initialSettings?.backgroundLevel = currentAutoBackgroundLevel
91	                
92	            } catch {
93	                // TODO: RAD-1108 - Обработать ошибочные состоянии получения дозы с сервиса и ошибки геолокации
94	            }
95	        }
96	    }
97	
98	    func saveCurrentDose() -> DoseSettings.BackgroundLevel? {
99	        switch mode {
100	        case .auto:
101	            if shouldAutoUpdateSettingsOnLoad {
102	                return nil
103	            }
104	            return currentAutoBackgroundLevel
105	        case .manual:
106	            return DoseSettings.BackgroundLevel(value: manualDose.selectedValue, mode: .manual)
107	        }
108	    }
109	}
